var doc = Rhino.RhinoDoc.ActiveDoc;
var selected = new List<Guid>();
foreach (var obj in doc.Objects.GetSelectedObjects(false, false)) selected.Add(obj.Id);
if (selected.Count == 0) return new { ok = false, error = "no objects selected" };
var target = System.IO.Path.Combine(System.IO.Path.GetTempPath(), "aware-drill.stl");
var cmd = $"_-Export \"{target}\" _Enter _Enter";
bool issued = Rhino.RhinoApp.RunScript(cmd, false);
return new { ok = issued, path = target, selected_count = selected.Count };
